313→
314→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
315→{
316→	// 统计每个 TypeID 的出现次数
317→	TMap<FName, int32> CountMap;
318→
319→	for (const FLFPUnitEntry& Unit : PartyUnits)
320→	{
321→		if (Unit.IsValid())
322→		{
323→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
324→		}
325→	}
326→	for (const FLFPUnitEntry& Unit : ReserveUnits)
327→	{
328→		if (Unit.IsValid())
329→		{
330→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
331→		}
332→	}
333→
334→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
335→	TArray<FLFPUnitEntry> Result;
336→	for (const auto& Pair : CountMap)
337→	{
338→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
339→		{
340→			FLFPUnitEntry Entry;
341→			Entry.TypeID = Pair.Key;
342→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
343→			Result.Add(Entry);
344→		}
345→	}
346→
347→	return Result;
348→}
349→
350→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
351→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
352→{
353→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
354→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
355→
356→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
357→	{
358→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
359→		return false;
360→	}
361→
362→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
363→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
364→
365→	// 验证两个源单位 TypeID 相同
366→	if (UnitA.TypeID != UnitB.TypeID)
367→	{
368→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
369→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
370→		return false;
371→	}
372→
373→	// 验证 TargetTypeID 在进化目标列表中
374→	if (!UnitRegistry)
375→	{
376→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
377→		return false;
378→	}
379→
380→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
381→	if (!Targets.Contains(TargetTypeID))
382→	{
383→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
384→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
385→		return false;
386→	}
387→
388→	// 创建进化后的新单位
389→	FLFPUnitEntry NewUnit;
390→	NewUnit.TypeID = TargetTypeID;
391→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
392→
393→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
394→	if (bSourceAIsParty == bSourceBIsParty)
395→	{
396→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
397→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
398→		ArrayA.RemoveAt(First);
399→		ArrayA.RemoveAt(Second);
400→	}
401→	else
402→	{
403→		ArrayA.RemoveAt(SourceAIndex);
404→		ArrayB.RemoveAt(SourceBIndex);
405→	}
406→
407→	TryAddUnit(NewUnit);
408→
409→	UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
410→		*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
411→
412→	return true;
413→}
