bool ULFPGameInstance::SpendGold(int32 Amount)
{
	if (Amount < 0)
	{
		return false;
	}

	if (!CanAffordGold(Amount))
	{
		UE_LOG(LogTemp, Warning, TEXT("金币不足: 需要 %d, 当前 %d"), Amount, Gold);
		return false;
	}

	Gold -= Amount;
	UE_LOG(LogTemp, Log, TEXT("金币变动: -%d, 当前: %d"), Amount, Gold);
	return true;
