	if (PartyUnits.IsValidIndex(SlotIndex))
	{
		UE_LOG(LogTemp, Log, TEXT("移除队伍槽 %d: %s"), SlotIndex, *PartyUnits[SlotIndex].TypeID.ToString());
		PartyUnits.RemoveAt(SlotIndex);
