{
	if (RelicID == NAME_None)
	{
		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: RelicID 无效"));
		return false;
	}

	if (!SpendGold(Price))
	{
		return false;
	}

	if (!TryAddOwnedRelic(RelicID))
	{
		AddGold(Price);
		return false;
	}

	UE_LOG(LogTemp, Log, TEXT("购买遗物成功: %s"), *RelicID.ToString());
