272→void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
273→{
274→	if (!SelectedNodeInfoText) return;
275→
276→	if (!Node)
277→	{
278→		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
279→		return;
280→	}
281→
282→	// 节点类型名
283→	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
284→	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);
285→
286→	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);
287→
288→	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
289→	{
290→		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
291→			Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
292→	}
293→	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
294→	{
295→		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
296→	}
297→	else if (Node->NodeType == ELFPWorldNodeType::WNT_Town)
298→	{
299→		Info += FString::Printf(TEXT(" | 建筑: %s | 商店: %s"), *Node->TownBuildingList, *Node->ShopID.ToString());
300→
301→		// 同步勾选框状态
302→		FString BL = Node->TownBuildingList;
303→		if (TownCheck_Shop) TownCheck_Shop->SetIsChecked(BL.Contains(TEXT("Shop")));
304→		if (TownCheck_EvolutionTower) TownCheck_EvolutionTower->SetIsChecked(BL.Contains(TEXT("EvolutionTower")));
305→		if (TownCheck_Teleport) TownCheck_Teleport->SetIsChecked(BL.Contains(TEXT("Teleport")));
306→		if (TownCheck_QuestNPC) TownCheck_QuestNPC->SetIsChecked(BL.Contains(TEXT("QuestNPC")));
307→		if (TownCheck_SkillNode) TownCheck_SkillNode->SetIsChecked(BL.Contains(TEXT("SkillNode")));
308→		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
309→	}
310→	else if (Node->NodeType == ELFPWorldNodeType::WNT_Shop)
311→	{
312→		Info += FString::Printf(TEXT(" | 商店: %s"), *Node->ShopID.ToString());
313→		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
314→	}
315→
316→	SelectedNodeInfoText->SetText(FText::FromString(Info));
317→}
