 25→void ALFPWorldMapPlayerController::BeginPlay()
 26→{
 27→	Super::BeginPlay();
 28→
 29→	// 设置输入模式
 30→	FInputModeGameAndUI InputMode;
 31→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 32→	InputMode.SetHideCursorDuringCapture(false);
 33→	SetInputMode(InputMode);
 34→	bShowMouseCursor = true;
 35→
 36→	// 设置 Enhanced Input
 37→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 38→	{
 39→		if (DefaultInputMapping)
 40→		{
 41→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 42→		}
 43→	}
 44→
 45→	// 场景切换淡入效果
 46→	if (PlayerCameraManager)
 47→	{
 48→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 49→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 50→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 51→	}
 52→
 53→	// 首帧跳过相机平滑插值
 54→	bSnapCameraNextFrame = true;
 55→}
 56→
 57→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 58→{
 59→	Super::Tick(DeltaTime);
 60→
 61→	if (bIsDragging)
 62→	{
 63→		DragTime += DeltaTime;
 64→	}
 65→
 66→	// 更新相机位置和旋转
 67→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 68→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 69→
 70→	// 相机旋转：俯视角
 71→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 72→
 73→	// 平滑插值并设置
 74→	FRotator CurrentRotation = GetControlRotation();
 75→	if (bSnapCameraNextFrame)
 76→	{
 77→		SetControlRotation(TargetRotation);
 78→	}
 79→	else
 80→	{
 81→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 82→	}
 83→
 84→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 85→	if (APawn* ControlledPawn = GetPawn())
 86→	{
 87→		if (bSnapCameraNextFrame)
 88→		{
 89→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 90→			ControlledPawn->SetActorLocation(TargetLocation);
 91→			bSnapCameraNextFrame = false;
 92→		}
 93→		else
 94→		{
 95→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 96→			ControlledPawn->SetActorLocation(
 97→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 98→			);
 99→		}
100→	}
101→}
