103→void ALFPWorldMapPlayerController::SetupInputComponent()
104→{
105→	Super::SetupInputComponent();
106→
107→	if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
108→	{
109→		// 基础操作
110→		EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
111→		EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
112→
113→		// 相机操作
114→		EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
115→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
116→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
117→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
118→		EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
119→
120→		// 编辑器切换
121→		EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
122→	}
123→}
124→
125→// ============== 输入处理 ==============
126→
127→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
128→{
129→	bIsDragging = false;
130→	if (DragTime > DragThresholdTime)
131→	{
132→		DragTime = 0.f;
133→		return;
134→	}
135→	DragTime = 0.f;
136→
137→	// 编辑器模式优先处理
138→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
139→	{
140→		// 射线检测点击的节点
141→		FHitResult HitResult;
142→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
143→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
144→
145→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
146→
147→		switch (CurrentTool)
148→		{
149→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
150→			{
151→				// 射线投射到 Z=0 平面获取世界坐标
152→				FVector WorldOrigin, WorldDirection;
153→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
154→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
155→				{
156→					float T = -WorldOrigin.Z / WorldDirection.Z;
157→					FVector HitPoint = WorldOrigin + WorldDirection * T;
158→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
159→				}
160→			}
161→			break;
162→
163→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
164→			if (ClickedNode)
165→			{
166→				WorldMapEditorComponent->SelectNode(ClickedNode);
167→				WorldMapEditorComponent->RemoveSelectedNode();
168→			}
169→			break;
170→
171→		case ELFPWorldMapEditorTool::WMET_MoveNode:
172→			if (ClickedNode)
173→			{
174→				WorldMapEditorComponent->SelectNode(ClickedNode);
175→			}
176→			else if (WorldMapEditorComponent->GetSelectedNode())
177→			{
178→				// 移动到点击位置
179→				FVector WorldOrigin, WorldDirection;
180→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
181→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
182→				{
183→					float T = -WorldOrigin.Z / WorldDirection.Z;
184→					FVector HitPoint = WorldOrigin + WorldDirection * T;
185→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
186→				}
187→			}
188→			break;
189→
190→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
191→			if (ClickedNode)
192→			{
193→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
194→			}
195→			break;
196→
197→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
198→			if (ClickedNode)
199→			{
200→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
201→			}
202→			break;
203→
204→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
205→			if (ClickedNode)
206→			{
207→				WorldMapEditorComponent->SelectNode(ClickedNode);
208→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
209→			}
210→			break;
211→
212→		default:
213→			break;
214→		}
215→		return;
216→	}
217→
218→	// 游戏模式：棋子移动中屏蔽点击
219→	ALFPWorldMapManager* Manager = GetWorldMapManager();
220→	if (Manager && Manager->IsPawnMoving()) return;
221→
222→	// 游戏模式：点击节点移动或进入
223→	FHitResult HitResult;
224→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
225→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
226→
227→	if (ClickedNode)
228→	{
229→		if (!Manager || !Manager->GetPlayerState()) return;
230→
231→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
232→
233→		// 点击当前节点 → 进入节点
234→		if (ClickedNode->NodeID == CurrentNodeID)
235→		{
236→			EnterNode(ClickedNode);
237→			return;
238→		}
239→
240→		// 点击相邻可达节点 → 移动
241→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
242→		if (ReachableIDs.Contains(ClickedNode->NodeID))
243→		{
244→			MoveToNode(ClickedNode);
245→		}
246→		else
247→		{
248→			// 不可达，只选中
249→			SelectNode(ClickedNode);
250→		}
251→	}
252→}
253→
254→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
255→{
256→	// 取消选中和可达高亮
257→	ClearReachableHighlight();
258→	if (SelectedNode)
259→	{
260→		SelectedNode->SetHighlighted(false);
261→		SelectedNode = nullptr;
262→	}
263→}
264→
265→void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
266→{
267→	if (!WorldMapEditorComponent) return;
268→
269→	WorldMapEditorComponent->ToggleEditorMode();
270→
271→	if (WorldMapEditorComponent->IsEditorActive())
272→	{
273→		// 创建或显示编辑器 Widget
274→		if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
275→		{
276→			WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
277→			if (WorldMapEditorWidget)
278→			{
279→				WorldMapEditorWidget->AddToViewport();
280→				WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
281→			}
282→		}
283→		else if (WorldMapEditorWidget)
