void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
{
	if (!SelectedNodeInfoText) return;

	if (!Node)
	{
		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
		return;
	}

	// 节点类型名
	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);

	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);

	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
	{
		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
			Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
	{
		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Town)
	{
		Info += FString::Printf(TEXT(" | 建筑: %s | 商店: %s"), *Node->TownBuildingList, *Node->ShopID.ToString());

		// 同步勾选框状态
		FString BL = Node->TownBuildingList;
		if (TownCheck_Shop) TownCheck_Shop->SetIsChecked(BL.Contains(TEXT("Shop")));
		if (TownCheck_EvolutionTower) TownCheck_EvolutionTower->SetIsChecked(BL.Contains(TEXT("EvolutionTower")));
		if (TownCheck_Teleport) TownCheck_Teleport->SetIsChecked(BL.Contains(TEXT("Teleport")));
		if (TownCheck_QuestNPC) TownCheck_QuestNPC->SetIsChecked(BL.Contains(TEXT("QuestNPC")));
		if (TownCheck_SkillNode) TownCheck_SkillNode->SetIsChecked(BL.Contains(TEXT("SkillNode")));
		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Shop)
	{
		Info += FString::Printf(TEXT(" | 商店: %s"), *Node->ShopID.ToString());
		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
	}

	SelectedNodeInfoText->SetText(FText::FromString(Info));
}

