void ULFPHireMarketWidget::RefreshUnitList()
{
	UnitButtons.Empty();
	ButtonToUnitIndexMap.Empty();

	if (Box_UnitList)
	{
		Box_UnitList->ClearChildren();
	}

	if (!CachedGameInstance || !CachedGameInstance->UnitRegistry || !Box_UnitList)
	{
		return;
