282	void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
283	{
284		if (!SelectedNodeInfoText) return;
285	
286		if (!Node)
287		{
288			SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
289			return;
290		}
291	
292		// 节点类型名
293		FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
294		TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);
295	
296		FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);
297	
298		if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
299		{
300			Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
301				Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
302		}
303		else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
304		{
305			Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
306		}
307		else if (Node->NodeType == ELFPWorldNodeType::WNT_Town)
308		{
309			Info += FString::Printf(TEXT(" | 建筑: %s | 商店: %s"), *Node->TownBuildingList, *Node->ShopID.ToString());
310	
311			// 同步勾选框状态
312			FString BL = Node->TownBuildingList;
313			if (TownCheck_Shop) TownCheck_Shop->SetIsChecked(BL.Contains(TEXT("Shop")));
314			if (TownCheck_EvolutionTower) TownCheck_EvolutionTower->SetIsChecked(BL.Contains(TEXT("EvolutionTower")));
315			if (TownCheck_Teleport) TownCheck_Teleport->SetIsChecked(BL.Contains(TEXT("Teleport")));
316			if (TownCheck_QuestNPC) TownCheck_QuestNPC->SetIsChecked(BL.Contains(TEXT("QuestNPC")));
317			if (TownCheck_SkillNode) TownCheck_SkillNode->SetIsChecked(BL.Contains(TEXT("SkillNode")));
318			if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
319		}
320		else if (Node->NodeType == ELFPWorldNodeType::WNT_Shop)
321		{
322			Info += FString::Printf(TEXT(" | 商店: %s"), *Node->ShopID.ToString());
323			if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
324		}
