void ULFPWorldMapEditorWidget::OnHireMarketIDChanged(const FText& Text, ETextCommit::Type CommitType)
{
	if (!EditorComponent) return;
	EditorComponent->SetBrushHireMarketID(FName(*Text.ToString()));
}

void ULFPWorldMapEditorWidget::OnTownBuildingCheckChanged(bool bIsChecked)
{
	SyncTownBuildingChecksToBrush();
}

void ULFPWorldMapEditorWidget::SyncTownBuildingChecksToBrush()
{
	if (!EditorComponent) return;

	TArray<FString> Parts;
	if (TownCheck_Shop && TownCheck_Shop->IsChecked()) Parts.Add(TEXT("Shop"));
	if (TownCheck_EvolutionTower && TownCheck_EvolutionTower->IsChecked()) Parts.Add(TEXT("EvolutionTower"));
	if (TownCheck_Teleport && TownCheck_Teleport->IsChecked()) Parts.Add(TEXT("Teleport"));
	if (TownCheck_QuestNPC && TownCheck_QuestNPC->IsChecked()) Parts.Add(TEXT("QuestNPC"));
	if (TownCheck_SkillNode && TownCheck_SkillNode->IsChecked()) Parts.Add(TEXT("SkillNode"));

	EditorComponent->SetBrushTownBuildingList(FString::Join(Parts, TEXT(";")));
}

// ============== 保存/加载 ==============

void ULFPWorldMapEditorWidget::OnSaveClicked()
{
	if (!EditorComponent || !WorldMapFileNameInput) return;

	FString MapName = WorldMapFileNameInput->GetText().ToString();
	if (MapName.IsEmpty())
	{
		UE_LOG(LogTemp, Warning, TEXT("世界地图编辑器: 请输入文件名"));
		return;
	}

	if (EditorComponent->SaveWorldMap(MapName))
	{
		UE_LOG(LogTemp, Log, TEXT("世界地图编辑器: 保存成功 - %s"), *MapName);
	}
}

void ULFPWorldMapEditorWidget::OnLoadClicked()
{
	if (!EditorComponent || !WorldMapFileNameInput) return;

	FString MapName = WorldMapFileNameInput->GetText().ToString();
	if (MapName.IsEmpty())
	{
		UE_LOG(LogTemp, Warning, TEXT("世界地图编辑器: 请输入文件名"));
		return;
	}

	if (EditorComponent->LoadWorldMap(MapName))
	{
		UE_LOG(LogTemp, Log, TEXT("世界地图编辑器: 加载成功 - %s"), *MapName);
	}
}

void ULFPWorldMapEditorWidget::OnNewMapClicked()
{
	if (EditorComponent) EditorComponent->NewWorldMap();
}

// ============== UI 更新 ==============

void ULFPWorldMapEditorWidget::UpdateToolIndicator(ELFPWorldMapEditorTool NewTool)
{
	if (!CurrentToolText) return;

	static const TMap<ELFPWorldMapEditorTool, FString> ToolNames = {
		{ELFPWorldMapEditorTool::WMET_None, TEXT("无")},
		{ELFPWorldMapEditorTool::WMET_PlaceNode, TEXT("放置节点")},
		{ELFPWorldMapEditorTool::WMET_RemoveNode, TEXT("删除节点")},
		{ELFPWorldMapEditorTool::WMET_MoveNode, TEXT("移动节点")},
		{ELFPWorldMapEditorTool::WMET_ConnectEdge, TEXT("连接边")},
		{ELFPWorldMapEditorTool::WMET_RemoveEdge, TEXT("删除边")},
		{ELFPWorldMapEditorTool::WMET_SetNodeParams, TEXT("设置参数")},
		{ELFPWorldMapEditorTool::WMET_EditBattleMap, TEXT("编辑战斗地图")},
	};

	if (const FString* Name = ToolNames.Find(NewTool))
	{
		CurrentToolText->SetText(FText::FromString(*Name));
	}
}

void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
{
	if (!SelectedNodeInfoText) return;

	if (!Node)
	{
		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
		return;
	}

	// 节点类型名
	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);

	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);

	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
	{
		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s | 金币: %d | 食物: %d"),
			Node->StarRating, *Node->BattleMapName, Node->BaseGoldReward, Node->BaseFoodReward);
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
	{
		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Town)
	{
		Info += FString::Printf(TEXT(" | 建筑: %s | 商店: %s"), *Node->TownBuildingList, *Node->ShopID.ToString());

		// 同步勾选框状态
		FString BL = Node->TownBuildingList;
		if (TownCheck_Shop) TownCheck_Shop->SetIsChecked(BL.Contains(TEXT("Shop")));
		if (TownCheck_EvolutionTower) TownCheck_EvolutionTower->SetIsChecked(BL.Contains(TEXT("EvolutionTower")));
		if (TownCheck_Teleport) TownCheck_Teleport->SetIsChecked(BL.Contains(TEXT("Teleport")));
		if (TownCheck_QuestNPC) TownCheck_QuestNPC->SetIsChecked(BL.Contains(TEXT("QuestNPC")));
		if (TownCheck_SkillNode) TownCheck_SkillNode->SetIsChecked(BL.Contains(TEXT("SkillNode")));
		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_Shop)
	{
		Info += FString::Printf(TEXT(" | 商店: %s"), *Node->ShopID.ToString());
		if (ShopIDInput) ShopIDInput->SetText(FText::FromName(Node->ShopID));
	}
	else if (Node->NodeType == ELFPWorldNodeType::WNT_HireMarket)
	{
		Info += FString::Printf(TEXT(" | 雇佣市场: %s"), *Node->HireMarketID.ToString());
		if (HireMarketIDInput) HireMarketIDInput->SetText(FText::FromName(Node->HireMarketID));
	}

	SelectedNodeInfoText->SetText(FText::FromString(Info));
}

